import { useEffect, useState } from 'react';
import api from '../../services/api';
import toast from 'react-hot-toast';

export default function HistorialCompras() {
  const [compras, setCompras] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchCompras = async () => {
      try {
        const res = await api.get('/compras');
        setCompras(res.data);
      } catch (error) {
        toast.error('Error al cargar compras');
      } finally {
        setLoading(false);
      }
    };
    fetchCompras();
  }, []);

  if (loading) return <div>Cargando...</div>;

  return (
    <div>
      <h1 className="text-2xl font-bold mb-4">Historial de Compras</h1>
      <div className="overflow-x-auto">
        <table className="min-w-full bg-white border">
          <thead>
            <tr className="bg-gray-100">
              <th className="py-2 px-4 border">ID</th>
              <th className="py-2 px-4 border">Proveedor</th>
              <th className="py-2 px-4 border">Usuario</th>
              <th className="py-2 px-4 border">Fecha</th>
              <th className="py-2 px-4 border">Total</th>
            </tr>
          </thead>
          <tbody>
            {compras.map(c => (
              <tr key={c.id}>
                <td className="py-2 px-4 border">{c.id}</td>
                <td className="py-2 px-4 border">{c.proveedor_nombre}</td>
                <td className="py-2 px-4 border">{c.usuario_nombre}</td>
                <td className="py-2 px-4 border">{new Date(c.fecha).toLocaleString()}</td>
                <td className="py-2 px-4 border">${c.total}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}
